  ('fire-eq-tech-moex-02760', 'fire-eq-tech', 'fire-eq-tech-moex-099-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '下列有關偵煙式探測器之敘述何者為錯誤？', '["居室樓地板面積在六十平方公尺以下時，應設在其出入口附近", "探測器裝設於距離牆壁或樑六十公分以上之位置", "探測器在走廊及通道，步行距離每三十公尺至少設置一個", "光電式分離型探測器之光軸高度，在天花板等高度百分之八十以上之位置"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "55e73ee84279", "answer_pdf_sha1": "5458d160a3a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "099080", "c": "701", "s": "300", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "警報與避難系統消防安全設備概要", "year": "099", "exam_name": "099年專技消防設備人員、地政士、專責報關、保險人員、特考中醫、語言治療、聽力考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
